// HasProfilePost applies the HasEdge predicate on the "profile_post" edge.
func HasProfilePost() predicate.ProfilePostItem {
	return predicate.ProfilePostItem(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ProfilePostTable, ProfilePostColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasProfilePostWith applies the HasEdge predicate on the "profile_post" edge with a given conditions (other predicates).
func HasProfilePostWith(preds ...predicate.ProfilePost) predicate.ProfilePostItem {
	return predicate.ProfilePostItem(func(s *sql.Selector) {
		step := newProfilePostStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProfilePostItem) predicate.ProfilePostItem {
	return predicate.ProfilePostItem(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProfilePostItem) predicate.ProfilePostItem {
	return predicate.ProfilePostItem(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProfilePostItem) predicate.ProfilePostItem {
	return predicate.ProfilePostItem(sql.NotPredicates(p))
}
